import matplotlib; matplotlib.use("Agg"); import matplotlib.pyplot as plt; import matplotlib.patches as patches; import numpy as np; fig, ax = plt.subplots(figsize=(5, 4)); ax.set_aspect("equal"); ax.axis("off"); ax.set_xlim(-1, 7); ax.set_ylim(-1, 5); A = np.array([0, 4]); B = np.array([0, 0]); C = np.array([6, 0]); triangle = plt.Polygon([A, B, C], fill=False, edgecolor="#1a1a1a", linewidth=1.5); ax.add_patch(triangle); square_size = 0.4; right_angle = plt.Polygon([[0, square_size], [square_size, square_size], [square_size, 0]], fill=False, edgecolor="#1a1a1a", linewidth=1); ax.add_patch(right_angle); ax.text(A[0] - 0.3, A[1], "A", fontsize=12, ha="right"); ax.text(B[0] - 0.3, B[1] - 0.3, "B", fontsize=12, ha="right"); ax.text(C[0] + 0.3, C[1] - 0.3, "C", fontsize=12, ha="left"); mid_hyp = (A + C) / 2; angle = np.degrees(np.arctan2(A[1] - C[1], A[0] - C[0])); ax.text(mid_hyp[0] + 0.4, mid_hyp[1] + 0.4, "10 cm", fontsize=12, rotation=angle + 180, ha="center", va="center"); plt.savefig("out.png", dpi=150)